import{_ as l,o as a,c as o,ag as t}from"./chunks/framework.D2Ob5GRY.js";const p=JSON.parse('{"title":"配置 LLM（首次必做）","description":"","frontmatter":{},"headers":[],"relativePath":"quickstart/configure-llm-basic.md","filePath":"quickstart/configure-llm-basic.md"}'),r={name:"quickstart/configure-llm-basic.md"};function i(s,e,n,c,d,h){return a(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="配置-llm-首次必做" tabindex="-1">配置 LLM（首次必做） <a class="header-anchor" href="#配置-llm-首次必做" aria-label="Permalink to &quot;配置 LLM（首次必做）&quot;">​</a></h1><blockquote><p>部署完成后第一件重要事情：配置至少一个 LLM 服务商，以便各功能模块能调用大模型。</p></blockquote><h2 id="为什么必须配置-llm" tabindex="-1">为什么必须配置 LLM <a class="header-anchor" href="#为什么必须配置-llm" aria-label="Permalink to &quot;为什么必须配置 LLM&quot;">​</a></h2><p>LinScio AI 的文献分析、论文写作、科普创作、数据分析、质控等模块均依赖大语言模型（LLM）生成与推理。未配置 LLM 时，相关功能将不可用或报错。</p><h2 id="支持哪些-llm-服务商" tabindex="-1">支持哪些 LLM 服务商 <a class="header-anchor" href="#支持哪些-llm-服务商" aria-label="Permalink to &quot;支持哪些 LLM 服务商&quot;">​</a></h2><ul><li><strong>DeepSeek</strong>（推荐新手）：国内直连，价格低，支持 deepseek-chat、deepseek-reasoner 等。</li><li><strong>阿里云 DashScope / 通义千问</strong>：国内直连，需阿里云账号与 API Key。</li><li><strong>OpenAI</strong>（如 GPT-4）：需代理访问，配置 <code>OPENAI_API_KEY</code> 及可选代理。</li><li><strong>Google Gemini</strong>：需代理访问，配置 <code>GEMINI_API_KEY</code> 及可选代理。</li><li><strong>Ollama</strong>（本地）：无需 API Key，在服务器或本机安装 Ollama 并配置 <code>OLLAMA_BASE_URL</code>。</li></ul><h2 id="快速配置-以-deepseek-为例-推荐新手" tabindex="-1">快速配置：以 DeepSeek 为例（推荐新手） <a class="header-anchor" href="#快速配置-以-deepseek-为例-推荐新手" aria-label="Permalink to &quot;快速配置：以 DeepSeek 为例（推荐新手）&quot;">​</a></h2><ol><li>打开 <a href="https://platform.deepseek.com/" target="_blank" rel="noreferrer">DeepSeek 开放平台</a>，注册/登录后进入 API 管理，创建 API Key 并复制。</li><li>登录 LinScio AI 系统，进入 <strong>系统设置</strong> → <strong>LLM 与文献配置</strong>。</li><li>找到「DeepSeek API Key」，将复制的 Key 粘贴并保存。</li><li>在「智能体配置」页（可选）为各智能体选择模型，如 DeepSeek Chat 或 DeepSeek R1；不选则使用默认档位。</li><li>返回任意使用 LLM 的模块（如论文写作、文献分析），发起一次对话或分析，验证是否正常返回结果。</li></ol><div class="tip custom-block"><p class="custom-block-title">提示</p><p>若仅配置 DeepSeek，多数场景无需配置代理；若使用 OpenAI 或 Gemini，需在「代理配置」中填写 HTTP/HTTPS 代理地址。</p></div><h2 id="配置完成后如何验证连接" tabindex="-1">配置完成后如何验证连接 <a class="header-anchor" href="#配置完成后如何验证连接" aria-label="Permalink to &quot;配置完成后如何验证连接&quot;">​</a></h2><ul><li><strong>方式一</strong>：在系统设置页保存 Key 后，若后端支持健康检查，可查看 LLM 服务状态是否变为可用。</li><li><strong>方式二</strong>：打开「论文写作」或「文献管理」等模块，输入一个问题或上传一篇文献并提问，能正常得到 AI 回复即表示连接成功。</li><li>若出现 401/403，多为 API Key 错误或过期；若出现超时，请检查网络与代理配置。</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/deployment/llm-providers.html">LLM 服务商配置详解</a></li><li><a href="/docs/deployment/proxy-config.html">网络与代理配置</a></li><li><a href="/docs/troubleshooting/common-errors.html#llm-调用失败">常见错误与解决方法</a></li></ul>',13)])])}const u=l(r,[["render",i]]);export{p as __pageData,u as default};
